import statistics, math
from collections import deque

@dataclass
class ZScoreDetector:
    window_size: int = 168    # 7 days of hourly windows
    z_threshold: float = -2.5 # standard deviations below mean → alarm
    _history: deque = field(default_factory=lambda: deque(maxlen=168))

    def update(self, current_mean: float) -> tuple[bool, float]:
        if len(self._history) < 10:
            self._history.append(current_mean)
            return False, 0.0
        baseline_mean = statistics.mean(self._history)
        baseline_std  = statistics.stdev(self._history) or 1e-9
        z = (current_mean - baseline_mean) / baseline_std
        self._history.append(current_mean)
        return z < self.z_threshold, z

    @property
    def baseline_mean(self) -> float:
        return statistics.mean(self._history) if self._history else 0.0

from enum import Enum

class DriftType(str, Enum):
    GRADUAL  = "gradual"    # CUSUM fired, Z-score did not
    SUDDEN   = "sudden"     # Z-score fired (z < threshold)
    COMPOUND = "compound"   # both fired simultaneously

@dataclass
class DriftSignal:
    stratum: str
    drift_type: DriftType
    severity: float     # absolute score drop from baseline
    cusum_value: float
    z_score: float
    window_start: str

def detect_drift(
    cusum: CUSUMDetector,
    zscore: ZScoreDetector,
    stratum: str,
    current_mean: float,
    window_start: str,
) -> DriftSignal | None:
    cusum_fired = cusum.update(current_mean)
    zscore_fired, z = zscore.update(current_mean)
    if not cusum_fired and not zscore_fired:
        return None
    if cusum_fired and zscore_fired:
        dtype = DriftType.COMPOUND
    elif zscore_fired:
        dtype = DriftType.SUDDEN
    else:
        dtype = DriftType.GRADUAL
    severity = zscore.baseline_mean - current_mean
    return DriftSignal(stratum, dtype, severity, cusum._cusum, z, window_start)

from enum import Enum

class DriftSeverity(str, Enum):
    LOW      = "low"       # 0.01–0.04 drop — monitor, investigate next sprint
    MEDIUM   = "medium"    # 0.05–0.09 drop — investigate within 24h
    HIGH     = "high"      # 0.10–0.19 drop — investigate within 1h, consider rollback
    CRITICAL = "critical"  # 0.20+ drop OR any safety flag spike — page on-call

def classify_severity(signal: DriftSignal, safety_flag_rate: float, baseline_flag_rate: float) -> DriftSeverity:
    # Safety flag spike always critical regardless of score drop
    if safety_flag_rate > baseline_flag_rate * 2.0 and safety_flag_rate > 0.02:
        return DriftSeverity.CRITICAL
    if signal.severity >= 0.20:
        return DriftSeverity.CRITICAL
    if signal.severity >= 0.10:
        return DriftSeverity.HIGH
    if signal.severity >= 0.05:
        return DriftSeverity.MEDIUM
    return DriftSeverity.LOW

from dataclasses import dataclass
from datetime import datetime, timezone
from enum import Enum

class SuddenDropAction(str, Enum):
    ROLLBACK   = "rollback"   # revert last prompt/config deploy
    HOTFIX     = "hotfix"     # patch in place without rollback
    HOLD       = "hold"       # pause new deploys, investigate first

@dataclass
class SuddenDropPlaybook:
    signal: DriftSignal
    deploy_log: list[dict]     # recent deploys [{time, kind, author, ref}]

    def correlating_deploy(self) -> dict | None:
        """Return the most recent deploy within 2h of the drift onset."""
        onset = datetime.fromisoformat(self.signal.window_start).replace(tzinfo=timezone.utc)
        for deploy in sorted(self.deploy_log, key=lambda d: d["time"], reverse=True):
            deploy_time = datetime.fromisoformat(deploy["time"]).replace(tzinfo=timezone.utc)
            delta_hours = (onset - deploy_time).total_seconds() / 3600
            if 0 <= delta_hours <= 2.0:
                return deploy
        return None

    def recommended_action(self) -> SuddenDropAction:
        deploy = self.correlating_deploy()
        if deploy is None:
            return SuddenDropAction.HOLD   # no obvious cause — investigate before acting
        if deploy["kind"] == "prompt":
            return SuddenDropAction.ROLLBACK
        return SuddenDropAction.HOTFIX

    def playbook_steps(self) -> list[str]:
        action = self.recommended_action()
        deploy = self.correlating_deploy()
        steps = [
            f"Severity HIGH: score dropped {self.signal.severity:.3f} below baseline",
            f"Recommended action: {action.value}",
        ]
        if deploy:
            steps.append(f"Correlating deploy: {deploy['kind']} at {deploy['time']} by {deploy['author']}")
            steps.append(f"Rollback ref: {deploy['ref']}")
        steps += [
            "Increase sample rate to 20% for affected stratum while investigating",
            "Post incident note in #claude-ops with drift signal summary",
            "Re-run baseline after fix and confirm scores recover",
        ]
        return steps

from dataclasses import dataclass
from datetime import datetime, timezone

@dataclass
class SafetyIncident:
    flagged_rate: float
    baseline_rate: float
    sample_count: int
    earliest_flagged: str

    @property
    def rate_multiplier(self) -> float:
        return self.flagged_rate / self.baseline_rate if self.baseline_rate else float("inf")

    def incident_brief(self) -> str:
        return (
            f"SAFETY INCIDENT: flag rate {self.flagged_rate:.3%} "
            f"({self.rate_multiplier:.1f}x baseline {self.baseline_rate:.3%}). "
            f"First flagged at {self.earliest_flagged}. "
            f"Sample count: {self.sample_count}"
        )

